//! wf-clean: a clean-room reimplementation of the tamarin-prover wellformedness
//! checker, derived purely from black-box oracle behavior. See
//! workspace/BEHAVIOR.md for the inferred behavioral spec.

pub mod checks;
pub mod formula;
pub mod pretty;
pub mod report;

pub use crate::ast::*;
pub use report::{
    insert_wf_before, render_report, topics, underline_topic, WfError, WfReport, SUCCESS_LINE,
...
    fact_lhs_occur_no_rhs, formula_terms, formula_terms_reducible, public_names_report,
    public_names_report_from_pairs,
};

pub mod order;
pub use order::*;

1	// Currently GPL 3.0 until granted permission by the following authors:
2	//   meiersi, jdreier, beschmi, rkunnema, sans-sucre, PhilipLukertWork,
3	//   kevinmorio, ValentinYuri, charlie-j, Nynko, arcz, Mathias-AURAND,
4	//   BTom-GH, rsasse, addap, felixlinker, xaDxelA, jWoc, yavivanov, and
5	//   other minor contributors (see upstream git history)
6	// Ported from upstream tamarin-prover sources:
7	//   lib/term/src/Term/LTerm.hs,
8	//   lib/term/src/Term/Term/FunctionSymbols.hs,
9	//   lib/term/src/Term/Term/Raw.hs,
10	//   lib/theory/src/Theory/Model/Formula.hs,
11	//   lib/theory/src/Theory/Text/Parser/Term.hs,
12	//   lib/theory/src/Theory/Text/Parser/Token.hs,
13	//   lib/theory/src/Theory/Tools/Wellformedness.hs, src/Main/Console.hs
14	
15	//! Faithful port of HS `checkTerms` (the "Formula terms" wellformedness
16	//! check) from `lib/theory/src/Theory/Tools/Wellformedness.hs:960-985`,
17	//! together with `formulaTerms` (`:917-920`) and `atomTerms` (`:908-915`).
18	//!
19	//! HS `checkTerms header maudeSig fm` collects all terms appearing in the
20	//! ATOMS of `fm` (via `formulaTerms`), then keeps as offenders every term
21	//! that is not `allowed`:
22	//!
23	//! ```text
24	//! allowed (Lit (Var (Bound _)))        = True   -- bound (quantified) variable
25	//! allowed (Lit (Con (Name PubName _))) = True   -- public constant 'c'
26	//! allowed (FUnion args)                = all allowed args  -- multiset union ++
27	//! allowed (FApp o args) | o `member` irreducible = all allowed args
28	//! allowed _                            = False
29	//!   where irreducible = irreducibleFunSyms maudeSig
30	//! ```
31	//!
32	//! Everything else — free variables, fresh/nat name literals, applications
33	//! of REDUCIBLE function symbols (sdec/adec/fst/snd/verify/...) — is an
34	//! offender.  Offenders are rendered with HS's `show` of the `VTerm c
35	//! (BVar v)` (e.g. `snd(Bound 1)`, `snd(sdec(Bound 3,Bound 2))`, `Free f`).
36	//!
37	//! The reducible/irreducible classification is sourced from the REAL
38	//! computed signature (`MaudeSig::irreducible_fun_syms`), exactly like HS's
39	//! `irreducibleFunSyms maudeSig`.  Because nullary functions (e.g. a
40	//! private `f/0`) parse as `Term::Var` in the surface AST, we resolve a
41	//! bare `Var` whose name+arity matches a signature funsym into an
42	//! application of that symbol before classifying it (so `K(f)` with
43	//! `f/0 [private]` is an irreducible `FApp f []`, allowed — matching HS).
44	
45	use std::collections::{BTreeMap, BTreeSet};
46	
47	use tamarin_parser::ast as p;
48	use tamarin_parser::ast::{Atom, BinOp, Formula, SortHint, SuffixSort, Term, VarSpec};
49	use tamarin_parser::wf::WfError;
50	use tamarin_term::function_symbols::{AcSym, FunSym};
51	use tamarin_term::maude_sig::MaudeSig;
52	
53	use crate::pretty_hpj::{fsep, punctuate, Doc};
54	
55	/// The fixed render budget for the "Formula terms" WF block, determined
56	/// empirically from HS output: HS lays the whole `/* WARNING ... */`
57	/// comment at `lineLength = 110` / `ribbon = 73` (see
58	/// [`crate::pretty_hpj::LINE_LENGTH`] / [`crate::pretty_hpj::RIBBON`]), but
59	/// the topic body is rendered already indented inside the surrounding
60	/// `/* ... */` warning frame, so the effective wrap column for the body is
61	/// 41 columns narrower than `lineLength`, i.e. 110 - 41 = 69. Boundary
62	/// verified against the real binary: an offender ending at column 69 stays
63	/// on the header line, at column 70 it wraps.
64	///
65	/// CAVEAT: this is a precomputed effective budget, NOT HS's own lineLength.
66	/// We do not reproduce the outer warning-frame nesting in the `Doc`
67	/// renderer, so if HS's `lineWidth` (Console.hs:236) or the WARNING-frame
68	/// indentation ever changes, this constant (used at both `render_with`
69	/// call sites in `render_block`) must be re-derived against the new binary.
70	const WF_WIDTH: usize = 69;
71	
72	/// The constant explanatory paragraph (HS `wrappedText "..."`).  The text
73	/// never varies, so its wrapped form (at `WF_WIDTH`) is constant too.
74	const ALLOWED_PARAGRAPH: &str = "The only allowed terms are public constants \
75	    and bound node and message variables. If you encounter free message \
76	    variables, then you might have forgotten a #-prefix. Sort prefixes can \
77	    only be dropped where this is unambiguous. Moreover, reducible function \
78	    symbols are disallowed.";
79	
80	// =============================================================================
81	// Resolved term: parser AST resolved against the signature, with De Bruijn
82	// indices assigned to bound variable uses.  Mirrors HS's `VTerm Name (BVar
83	// LVar)` shape closely enough to (a) run `allowed` and (b) `show`.
84	// =============================================================================
85	
86	/// A function-symbol head.
87	#[derive(Debug, Clone)]
88	enum Head {
89	    /// A NoEq (free) application whose head symbol is `reducible == false`
90	    /// iff it is in the irreducible set.
91	    App { name: String, reducible: bool },
92	    /// An AC function symbol (Union/Mult/Xor/NatPlus).  `reducible` is set
93	    /// from the signature's irreducible AC set, EXCEPT Union which HS
94	    /// special-cases as always-allowed-if-args-allowed (`FUnion`).
95	    Ac { sym: AcSym, reducible: bool },
96	}
97	
98	/// A resolved term in De-Bruijn form, sufficient to evaluate `allowed` and
99	/// to `show` like HS.
100	#[derive(Debug, Clone)]
101	enum RTerm {
102	    /// A bound variable: `Bound n`.
103	    Bound(u32),
104	    /// A free variable: `Free <lvar-rendering>`.
105	    Free(VarSpec),
106	    /// A public constant `'c'` (HS `Con (Name PubName _)`).
107	    PubConst(String),
108	    /// A fresh-name literal `~'n'` (HS `Con (Name FreshName _)`).
109	    FreshConst(String),
110	    /// A nat-name literal `%'n'` (HS `Con (Name NatName _)`).
111	    NatConst(String),
112	    /// An application `head(args)`.
113	    App(Head, Vec<RTerm>),
114	}
115	
116	// =============================================================================
117	// Signature lookup
118	// =============================================================================
119	
120	/// Index of irreducible function symbols by (name, arity).  Mirrors
121	/// `irreducibleFunSyms maudeSig` membership tests.
122	struct Irreducible {
123	    /// Arities (keyed by name-bytes) of every irreducible NoEq symbol.
124	    noeq: BTreeMap<Vec<u8>, BTreeSet<usize>>,
125	    /// Irreducible AC symbols (e.g. `Mult`, `NatPlus` are irreducible; `Xor`
126	    /// is reducible).  HS keys on the `FunSym` value, which for AC ops is
127	    /// `AC <ACSym>`.
128	    ac: BTreeSet<AcSym>,
129	    /// Names of all nullary NoEq symbols in the FULL signature.  Used to
130	    /// resolve a bare `Var` whose name is a declared nullary funsym into an
131	    /// application (mirrors HS resolving `f/0` to `FApp f []`).
132	    nullary_names: BTreeSet<Vec<u8>>,
133	}
134	
135	impl Irreducible {
136	    fn from_sig(sig: &MaudeSig) -> Self {
137	        let mut noeq: BTreeMap<Vec<u8>, BTreeSet<usize>> = BTreeMap::new();
138	        let mut ac = BTreeSet::new();
139	        for s in &sig.irreducible_fun_syms {
140	            match s {
141	                FunSym::NoEq(n) => {
142	                    noeq.entry(n.name.to_vec()).or_default().insert(n.arity);
143	                }
144	                FunSym::Ac(a) => {
145	                    ac.insert(*a);
146	                }
147	                _ => {}
148	            }
149	        }
150	        let mut nullary_names = BTreeSet::new();
151	        for s in sig.fun_syms.iter() {
152	            if let FunSym::NoEq(n) = s {
153	                if n.arity == 0 {
154	                    nullary_names.insert(n.name.to_vec());
155	                }
156	            }
157	        }
158	        Irreducible { noeq, ac, nullary_names }
159	    }
160	
161	    /// Is the NoEq symbol `name/arity` irreducible?
162	    fn is_irreducible(&self, name: &str, arity: usize) -> bool {
163	        self.noeq.get(name.as_bytes()).is_some_and(|s| s.contains(&arity))
164	    }
165	
166	    /// Is the AC symbol `a` irreducible?
167	    fn is_ac_irreducible(&self, a: AcSym) -> bool {
168	        self.ac.contains(&a)
169	    }
170	
171	    /// Is `name` a declared nullary funsym?
172	    fn nullary_named(&self, name: &str) -> bool {
173	        self.nullary_names.contains(name.as_bytes())
174	    }
175	}
176	
177	// =============================================================================
178	// Public entry point
179	// =============================================================================
180	
181	/// Port of HS `formulaReports`'s `checkTerms` arm (Wellformedness.hs:1003),
182	/// for every lemma + restriction formula (in theory order, lemmas before
183	/// restrictions — HS `annFormulas`).  Macros must already be expanded by
184	/// the caller (HS applies `applyMacroInFormula` first).
185	pub fn check_terms_wf(thy: &p::Theory, sig: &MaudeSig) -> Vec<WfError> {
186	    let irr = Irreducible::from_sig(sig);
187	    let mut out = Vec::new();
188	
189	    // HS folds surplus args of an arity-1 function into a pair at PARSE time
190	    // (`naryOpApp` `k == 1`, Theory/Text/Parser/Term.hs:84-87), so the AST the
191	    // wf check inspects already carries `h(<a, b>)` (an irreducible `h/1`
192	    // applied to a pair), NOT `h(a, b)`.  RS's arity-unaware parser keeps the
193	    // surplus args, so without this fold a unary `h(a, b)` resolves to a
194	    // non-existent reducible `h/2` and is spuriously flagged "uses terms of
195	    // the wrong form: reducible function symbols are disallowed".  Fold first
196	    // (mirrors the lemma/restriction pretty-printer in pretty_theory.rs).
197	    let arity1 = crate::elaborate::arity1_noeq_names(sig);
198	
199	    // HS `annFormulas = lemmas <|> restrictions` — all lemmas (theory
200	    // order) then all restrictions (theory order).
201	    let mut lemmas: Vec<(String, Formula)> = Vec::new();
202	    let mut restrictions: Vec<(String, Formula)> = Vec::new();
203	    for item in &thy.items {
204	        match item {
205	            p::TheoryItem::Lemma(l) => lemmas.push((
206	                format!("Lemma `{}'", l.name),
207	                crate::elaborate::rewrite_arity1_formula(&l.formula, &arity1))),
208	            p::TheoryItem::Restriction(r) | p::TheoryItem::LegacyAxiom(r) =>
209	                restrictions.push((
210	                    format!("Restriction `{}'", r.name),
211	                    crate::elaborate::rewrite_arity1_formula(&r.formula, &arity1))),
212	            _ => {}
213	        }
214	    }
215	    for (header, fm) in lemmas.into_iter().chain(restrictions) {
216	        if let Some(msg) = check_one(&header, &fm, &irr) {
217	            out.push(WfError::new("Formula terms", msg));
218	        }
219	    }
220	    out
221	}
222	
223	/// Run `checkTerms` for a single annotated formula.  Returns the formatted
224	/// WF block (matching HS byte-for-byte) iff there are offenders.
225	fn check_one(header: &str, fm: &Formula, irr: &Irreducible) -> Option<String> {
226	    let mut terms: Vec<RTerm> = Vec::new();
227	    collect_formula_terms(fm, &mut Vec::new(), irr, &mut terms);
228	
229	    let offenders: Vec<String> = terms
230	        .iter()
231	        .filter(|t| !allowed(t))
232	        .map(show_rterm)
233	        .collect();
234	
235	    if offenders.is_empty() {
236	        return None;
237	    }
238	    Some(render_block(header, &offenders))
239	}
