241	// =============================================================================
242	// formulaTerms / atomTerms with De-Bruijn assignment
243	// =============================================================================
244	
245	/// A binder in scope, tracked for De-Bruijn assignment.  `scope[0]` is the
246	/// OUTERMOST binder; `scope[last]` the innermost.  The De-Bruijn index of a
247	/// binder at position `i` is `scope.len() - 1 - i` (count of binders inner
248	/// to it).
249	type Scope = Vec<VarSpec>;
250	
251	/// HS `formulaTerms`: collect the terms from every atom.  Recurses through
252	/// connectives and quantifiers, pushing binders onto `scope` so that
253	/// variable uses inside the body get the right De-Bruijn index.
254	fn collect_formula_terms(
255	    fm: &Formula,
256	    scope: &mut Scope,
257	    irr: &Irreducible,
258	    out: &mut Vec<RTerm>,
259	) {
260	    match fm {
261	        Formula::True | Formula::False => {}
262	        Formula::Atom(a) => collect_atom_terms(a, scope, irr, out),
263	        Formula::Not(g) => collect_formula_terms(g, scope, irr, out),
264	        Formula::And(a, b)
265	        | Formula::Or(a, b)
266	        | Formula::Implies(a, b)
267	        | Formula::Iff(a, b) => {
268	            collect_formula_terms(a, scope, irr, out);
269	            collect_formula_terms(b, scope, irr, out);
270	        }
271	        Formula::Forall(vs, body) | Formula::Exists(vs, body) => {
272	            // HS `foldr (hinted q) f vs` quantifies the LAST var innermost.
273	            // Pushing in source order makes the last-listed var the
274	            // innermost binder (highest scope position) — exactly the
275	            // De-Bruijn nesting HS produces.
276	            let pushed = vs.len();
277	            for v in vs {
278	                scope.push(v.clone());
279	            }
280	            collect_formula_terms(body, scope, irr, out);
281	            for _ in 0..pushed {
282	                scope.pop();
283	            }
284	        }
285	    }
286	}
287	
288	/// HS `atomTerms` — the terms a single atom contributes.
289	fn collect_atom_terms(a: &Atom, scope: &Scope, irr: &Irreducible, out: &mut Vec<RTerm>) {
290	    match a {
291	        // Action i fa  ->  i : factTerms fa   (temporal var THEN fact args)
292	        Atom::Action(fact, tp) => {
293	            out.push(resolve_term(tp, scope, irr, TermPos::Temporal));
294	            for arg in &fact.args {
295	                out.push(resolve_term(arg, scope, irr, TermPos::Message));
296	            }
297	        }
298	        // EqE t s -> [t, s]
299	        Atom::Eq(x, y) => {
300	            out.push(resolve_term(x, scope, irr, TermPos::Message));
301	            out.push(resolve_term(y, scope, irr, TermPos::Message));
302	        }
303	        // Subterm i j -> [i, j]
304	        Atom::Subterm(x, y) => {
305	            out.push(resolve_term(x, scope, irr, TermPos::Message));
306	            out.push(resolve_term(y, scope, irr, TermPos::Message));
307	        }
308	        // Less i j -> [i, j]  (temporal node vars)
309	        Atom::Less(x, y) => {
310	            out.push(resolve_term(x, scope, irr, TermPos::Temporal));
311	            out.push(resolve_term(y, scope, irr, TermPos::Temporal));
312	        }
313	        // The multiset-`(<)` ordering relation: operands are message terms.
314	        Atom::LessMset(x, y) => {
315	            out.push(resolve_term(x, scope, irr, TermPos::Message));
316	            out.push(resolve_term(y, scope, irr, TermPos::Message));
317	        }
318	        // Last i -> [i]  (temporal)
319	        Atom::Last(tp) => {
320	            out.push(resolve_term(tp, scope, irr, TermPos::Temporal));
321	        }
322	        // Syntactic (predicate) atoms contribute no real terms
323	        // (HS `atomTerms (Syntactic _) = []`).
324	        Atom::Pred(_) => {}
325	    }
326	}
327	
328	/// The syntactic position of a term, which fixes the implicit sort of an
329	/// untagged variable use (mirrors the parser's positional sort inference).
330	#[derive(Clone, Copy, PartialEq)]
331	enum TermPos {
332	    /// Argument of `@`, `<`, `last` — implicitly a node (temporal) var.
333	    Temporal,
334	    /// A message-position term (fact arg, equality operand, ...).
335	    Message,
336	}
337	
338	// =============================================================================
339	// Term resolution: parser AST -> RTerm (with De-Bruijn + signature lookup)
340	// =============================================================================
341	
342	fn resolve_term(t: &Term, scope: &Scope, irr: &Irreducible, pos: TermPos) -> RTerm {
343	    match t {
344	        Term::Var(v) => resolve_var(v, scope, irr, pos),
345	        Term::PubLit(s) => RTerm::PubConst(s.clone()),
346	        Term::FreshLit(s) => RTerm::FreshConst(s.clone()),
347	        Term::NatLit(s) => RTerm::NatConst(s.clone()),
348	        // Bare numeric/`1`/`%1` literals: HS treats these as nullary
349	        // irreducible Public constructors.  The DH `1` is `oneSymString =
350	        // "one"` and the nat `%1` is `natOneSymString = "tone"`
351	        // (FunctionSymbols.hs:134,144); both are arity-0 Public Constructors
352	        // and hence always `allowed`, so the head name is never rendered as
353	        // an offender — but we still use the HS-faithful names here.
354	        Term::Number(n) => RTerm::PubConst(n.to_string()),
355	        Term::NumberOne => RTerm::App(Head::App { name: "one".into(), reducible: false }, vec![]),
356	        Term::NatOne => RTerm::App(Head::App { name: "tone".into(), reducible: false }, vec![]),
357	        Term::DhNeutral => RTerm::App(Head::App { name: "DH_neutral".into(), reducible: false }, vec![]),
358	        Term::App(name, args) => resolve_app(name, args, scope, irr),
359	        Term::AlgApp(name, a, b) => {
360	            // `op{a}b` == `op(a, b)`.
361	            let args = vec![
362	                resolve_term(a, scope, irr, TermPos::Message),
363	                resolve_term(b, scope, irr, TermPos::Message),
364	            ];
365	            resolve_named(name, args, irr)
366	        }
367	        Term::Pair(items) => {
368	            // `<a, b, c>` is right-nested `pair(a, pair(b, c))`.
369	            let resolved: Vec<RTerm> = items
370	                .iter()
371	                .map(|i| resolve_term(i, scope, irr, TermPos::Message))
372	                .collect();
373	            build_pair(resolved, irr)
374	        }
375	        Term::Diff(a, b) => {
376	            let args = vec![
377	                resolve_term(a, scope, irr, TermPos::Message),
378	                resolve_term(b, scope, irr, TermPos::Message),
379	            ];
380	            resolve_named("diff", args, irr)
381	        }
382	        Term::BinOp(op, a, b) => {
383	            let ra = resolve_term(a, scope, irr, TermPos::Message);
384	            let rb = resolve_term(b, scope, irr, TermPos::Message);
385	            match op {
386	                // `^` (exp) is a NoEq symbol; the rest are AC symbols.
387	                BinOp::Exp => resolve_named("exp", vec![ra, rb], irr),
388	                BinOp::Union => resolve_ac(AcSym::Union, vec![ra, rb], irr),
389	                BinOp::Mult => resolve_ac(AcSym::Mult, vec![ra, rb], irr),
390	                BinOp::Xor => resolve_ac(AcSym::Xor, vec![ra, rb], irr),
391	                BinOp::NatPlus => resolve_ac(AcSym::NatPlus, vec![ra, rb], irr),
392	            }
393	        }
394	        Term::PatMatch(inner) => resolve_term(inner, scope, irr, pos),
395	    }
396	}
397	
398	fn resolve_app(name: &str, args: &[Term], scope: &Scope, irr: &Irreducible) -> RTerm {
399	    let resolved: Vec<RTerm> = args
400	        .iter()
401	        .map(|a| resolve_term(a, scope, irr, TermPos::Message))
402	        .collect();
403	    resolve_named(name, resolved, irr)
404	}
405	
406	/// Build a NoEq application node from a name + already-resolved args,
407	/// classifying the head as reducible/irreducible from the real signature.
408	fn resolve_named(name: &str, args: Vec<RTerm>, irr: &Irreducible) -> RTerm {
409	    let arity = args.len();
410	    let reducible = !irr.is_irreducible(name, arity);
411	    RTerm::App(Head::App { name: name.to_string(), reducible }, args)
412	}
413	
414	/// Build an AC application node, classifying via the irreducible AC set.
415	/// Union is HS-special-cased (`FUnion` — always allowed-if-args-allowed)
416	/// so we force `reducible = false` for it regardless of set membership.
417	fn resolve_ac(sym: AcSym, args: Vec<RTerm>, irr: &Irreducible) -> RTerm {
418	    let reducible = if matches!(sym, AcSym::Union) {
419	        false
420	    } else {
421	        !irr.is_ac_irreducible(sym)
422	    };
423	    RTerm::App(Head::Ac { sym, reducible }, args)
424	}
425	
426	/// Right-nested pair construction matching HS's `<a,b,c> = pair(a, pair(b,
427	/// c))`.  `pair` is irreducible.
428	fn build_pair(mut items: Vec<RTerm>, irr: &Irreducible) -> RTerm {
429	    if items.is_empty() {
430	        return resolve_named("pair", vec![], irr);
431	    }
432	    if items.len() == 1 {
433	        return items.pop().unwrap();
434	    }
435	    let head = items.remove(0);
436	    let rest = build_pair(items, irr);
437	    resolve_named("pair", vec![head, rest], irr)
438	}
439	
440	/// Resolve a variable USE to either a `Bound n` (if a matching binder is in
441	/// scope) or `Free` (otherwise) — UNLESS the name is a declared nullary
442	/// function symbol with no matching binder, in which case it is an
443	/// irreducible `FApp name []` (HS resolves `f/0` to `FApp f []`).
444	fn resolve_var(v: &VarSpec, scope: &Scope, irr: &Irreducible, pos: TermPos) -> RTerm {
445	    if let Some(idx) = lookup_bound(v, scope, pos) {
446	        return RTerm::Bound(idx);
447	    }
448	    // Not bound: a bare untagged name that is a declared nullary funsym
449	    // is an application (e.g. private `f/0` parsed as Var("f")).
450	    if matches!(v.sort, SortHint::Untagged) && irr.nullary_named(&v.name) {
451	        return resolve_named(&v.name, vec![], irr);
452	    }
453	    RTerm::Free(v.clone())
454	}
455	
456	/// Find the innermost binder matching `v` and return its De-Bruijn index.
457	///
458	/// HS binds a use to its binder via full `LVar` equality — name AND sort AND
459	/// idx (`quantify x = ... | v == x = Bound i`, Formula.hs:340-345; `LVar` `Eq`
460	/// compares `idx`, sort and name, LTerm.hs:516-517). We reproduce this exactly
461	/// on the sort-*kind*: the use's sort is concrete in HS, never approximate.
462	/// The parser assigns every variable a concrete `LSort` before `quantify`
463	/// runs (Formula.hs:114 `standardFormula msgvar nodevar`):
464	///   - a message-position variable is parsed by `msgvar`
465	///     (`sortedLVar [LSortFresh, LSortPub, LSortNat, LSortMsg]`,
466	///     Token.hs:440-441), so an *untagged* message use takes the
467	///     `mkPrefixParser LSortMsg` arm (the bare `LSortMsg -> pure ()` case,
468	///     Token.hs:424-426) and gets the concrete sort `LSortMsg` — hence
469	///     `kind_of(SortHint::Untagged) == KIND_MSG` is exact, not approximate;
470	///   - a temporal-position variable is parsed by `nodevar`
471	///     (`LSortNode`, Token.hs:444-447), hence `KIND_NODE`.
472	///
473	/// `quantify`'s `v == x` then compares sort exactly, so an untagged `x` binds
474	/// only to a `LSortMsg` binder, never to a `~x`/`$x`/`%x`/`#x` binder of the
475	/// same name+idx. The `idx` comparison likewise keeps `x.1` and `x.2` distinct.
476	fn lookup_bound(v: &VarSpec, scope: &Scope, pos: TermPos) -> Option<u32> {
477	    // The use's concrete sort-kind (Temporal positions are LSortNode; message
478	    // positions take the use's sigil, or LSortMsg when untagged — see above).
479	    let expected: u8 = match pos {
480	        TermPos::Temporal => KIND_NODE,
481	        TermPos::Message => kind_of(&v.sort),
482	    };
483	    // Search innermost (last) first.
484	    for (i, b) in scope.iter().enumerate().rev() {
485	        if b.name != v.name || b.idx != v.idx {
486	            continue;
487	        }
488	        if kind_of(&b.sort) == expected {
489	            let db = (scope.len() - 1 - i) as u32;
490	            return Some(db);
491	        }
492	    }
493	    None
494	}
495	
496	const KIND_FRESH: u8 = 0;
497	const KIND_PUB: u8 = 1;
498	const KIND_NODE: u8 = 2;
499	const KIND_NAT: u8 = 3;
500	const KIND_MSG: u8 = 4;
501	
502	fn kind_of(s: &SortHint) -> u8 {
503	    match s {
504	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => KIND_FRESH,
505	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => KIND_PUB,
506	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => KIND_NODE,
507	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => KIND_NAT,
508	        SortHint::Msg | SortHint::Suffix(SuffixSort::Msg) => KIND_MSG,
509	        SortHint::Untagged => KIND_MSG,
510	    }
511	}
512	
513	// =============================================================================
514	// `allowed` predicate (HS Wellformedness.hs:978-985)
515	// =============================================================================
516	
517	fn allowed(t: &RTerm) -> bool {
518	    match t {
519	        RTerm::Bound(_) => true,
520	        RTerm::PubConst(_) => true,
521	        RTerm::App(Head::App { reducible, .. }, args)
522	        | RTerm::App(Head::Ac { reducible, .. }, args) => {
523	            !*reducible && args.iter().all(allowed)
524	        }
525	        // Free vars, fresh/nat name constants -> offenders.
526	        RTerm::Free(_) | RTerm::FreshConst(_) | RTerm::NatConst(_) => false,
527	    }
528	}
