530	// =============================================================================
531	// `show` of an offender term (HS `Show (VTerm Name (BVar LVar))`)
532	// =============================================================================
533	
534	fn show_rterm(t: &RTerm) -> String {
535	    let mut s = String::new();
536	    write_rterm(t, &mut s);
537	    s
538	}
539	
540	fn write_rterm(t: &RTerm, out: &mut String) {
541	    match t {
542	        RTerm::Bound(n) => {
543	            out.push_str("Bound ");
544	            out.push_str(&n.to_string());
545	        }
546	        RTerm::Free(v) => {
547	            out.push_str("Free ");
548	            out.push_str(&show_lvar(v));
549	        }
550	        // HS `Show Name`: PubName -> `'n'`, FreshName -> `~'n'`,
551	        // NatName -> `%'n'`.
552	        RTerm::PubConst(n) => {
553	            out.push('\'');
554	            out.push_str(n);
555	            out.push('\'');
556	        }
557	        RTerm::FreshConst(n) => {
558	            out.push_str("~'");
559	            out.push_str(n);
560	            out.push('\'');
561	        }
562	        RTerm::NatConst(n) => {
563	            out.push_str("%'");
564	            out.push_str(n);
565	            out.push('\'');
566	        }
567	        RTerm::App(head, args) => {
568	            // HS `Show (Term a)` (Term/Raw.hs:219-227):
569	            //   FApp (NoEq (s,_)) [] -> s
570	            //   FApp (NoEq (s,_)) as -> s ++ "(" ++ intercalate "," ... ++ ")"
571	            //   FApp (AC o) as       -> show o ++ "(" ++ ... ++ ")"
572	            // ACSym derives Show as the constructor name (Union/Mult/Xor/NatPlus).
573	            let name: &str = match head {
574	                Head::App { name, .. } => name.as_str(),
575	                Head::Ac { sym, .. } => match sym {
576	                    AcSym::Union => "Union",
577	                    AcSym::Mult => "Mult",
578	                    AcSym::Xor => "Xor",
579	                    AcSym::NatPlus => "NatPlus",
580	                },
581	            };
582	            out.push_str(name);
583	            if !args.is_empty() {
584	                out.push('(');
585	                for (i, a) in args.iter().enumerate() {
586	                    if i > 0 {
587	                        out.push(',');
588	                    }
589	                    write_rterm(a, out);
590	                }
591	                out.push(')');
592	            }
593	        }
594	    }
595	}
596	
597	/// HS `Show LVar`: `sortPrefix s ++ body`, where body is the name (or, if
598	/// `idx /= 0`, `name.idx`; if the name is empty, just the index).
599	/// Shared with the message-derivation probe (`deriv_check`).
600	pub(crate) fn show_lvar(v: &VarSpec) -> String {
601	    let prefix = match v.sort {
602	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => "~",
603	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => "$",
604	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => "#",
605	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => "%",
606	        _ => "",
607	    };
608	    let body = if v.name.is_empty() {
609	        v.idx.to_string()
610	    } else if v.idx == 0 {
611	        v.name.clone()
612	    } else {
613	        format!("{}.{}", v.name, v.idx)
614	    };
615	    format!("{}{}", prefix, body)
616	}
