1077	/// Lay out `tokens` after `prefix` with a fillSep (paragraph fill): place a
1078	/// token on the current line while `col + 1 + width <= width`, else break to a
1079	/// new line indented `indent`. Each token but the last carries a trailing
1080	/// comma. Matches the oracle's wrapping at column 69 (probes r3_wrap/r3_w2).
1081	fn fill_after_prefix(prefix: &str, tokens: &[String], indent: usize, width: usize) -> String {
1082	    let mut line = prefix.to_string();
1083	    let mut col = prefix.chars().count();
1084	    let pad = " ".repeat(indent);
1085	    let n = tokens.len();
1086	    for (i, tok) in tokens.iter().enumerate() {
1087	        let piece = if i + 1 < n {
1088	            format!("{},", tok)
1089	        } else {
1090	            tok.clone()
1091	        };
1092	        let w = piece.chars().count();
1093	        if col + 1 + w <= width {
1094	            line.push(' ');
1095	            line.push_str(&piece);
1096	            col += 1 + w;
1097	        } else {
1098	            line.push('\n');
1099	            line.push_str(&pad);
1100	            line.push_str(&piece);
1101	            col = indent + w;
1102	        }
1103	    }
1104	    line
