1284	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1285	            for f in facts {
1286	                for a in &f.args {
1287	                    collect_nat_issues(a, &mut entries);
1288	                }
1289	            }
1290	        }
1291	    }
1292	    if entries.is_empty() {
1293	        vec![]
1294	    } else {
1295	        vec![WfError::new(T_NAT, entries.join("\n  \n"))]
1296	    }
1297	}
1298	
1299	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
1300	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
1301	        let term_pp = pp_term(t);
1302	        let mut vs = Vec::new();
1303	        collect_term_vars(t, &mut vs);
1304	        for v in vs {
1305	            if v.sort != SortHint::Nat {
1306	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
1307	                if !out.contains(&entry) {
1308	                    out.push(entry);
1309	                }
1310	            }
1311	        }
1312	    }
1313	    // recurse
1314	    match t {
1315	        Term::App(_, args) | Term::Pair(args) => {
1316	            for a in args {
1317	                collect_nat_issues(a, out);
1318	            }
1319	        }
1320	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1321	            collect_nat_issues(a, out);
1322	            collect_nat_issues(b, out);
1323	        }
1324	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
1325	        _ => {}
1326	    }
1327	}
1328	
1329	// ---------------------------------------------------------------------------
1330	// 13. Subterm Convergence Warning
1331	// ---------------------------------------------------------------------------
1332	
1333	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
1334	    let mut bad: Vec<String> = Vec::new();
1335	    for it in &thy.items {
1336	        if let TheoryItem::Equations { convergent, eqs } = it {
1337	            if *convergent {
1338	                continue; // user asserted convergence
1339	            }
1340	            for eq in eqs {
1341	                if !is_subterm(&eq.rhs, &eq.lhs) {
1342	                    bad.push(format!("    {} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs)));
1343	                }
1344	            }
1345	        }
1346	    }
1347	    if bad.is_empty() {
1348	        return vec![];
1349	    }
1350	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
1351	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
1352	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
1353	    vec![WfError::new(T_SUBTERM, msg)]
1354	}
1355	
1356	/// Structural subterm test: does `small` occur as a subterm of `big`?
1357	fn is_subterm(small: &Term, big: &Term) -> bool {
1358	    if small == big {
1359	        return true;
1360	    }
1361	    match big {
1362	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
1363	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1364	            is_subterm(small, a) || is_subterm(small, b)
1365	        }
1366	        Term::PatMatch(inner) => is_subterm(small, inner),
1367	        _ => false,
1368	    }
1369	}
