56	/// Parse an argument vector (excluding argv[0]/program name).
57	pub fn parse(argv: &[String]) -> Result<Command, CliError> {
58	    // 1. Determine mode and the slice of tokens to parse within it.
59	    let (mode, rest): (Mode, &[String]) = match argv.first() {
60	        // Truly empty argv is not observable through the oracle; treated as the
61	        // default-mode no-input case (documented inference).
62	        None => return Err(errors::no_input_files(Mode::Batch)),
63	        Some(first) if first.starts_with('-') => (Mode::Batch, argv),
64	        Some(first) => {
65	            let matches = Mode::prefix_matches(first);
66	            match matches.len() {
67	                1 => (matches[0].1, &argv[1..]),
68	                0 => (Mode::Batch, argv), // not a mode prefix -> a FILE
69	                _ => {
70	                    let names: Vec<&str> = matches.iter().map(|(n, _)| *n).collect();
71	                    return Err(errors::ambiguous_mode(first, &names));
72	                }
73	            }
74	        }
75	    };
76	
77	    // 2. Left-to-right token scan within the chosen mode.
78	    let table = flags_for(mode);
79	    let mut options = Options::default();
80	    let mut positional: Vec<String> = Vec::new();
81	
82	    for tok in rest {
83	        if let Some(body) = tok.strip_prefix("--") {
84	            // Long flag: `--name` or `--name=value`.
85	            let (name, value) = match body.split_once('=') {
86	                Some((n, v)) => (n, Some(v.to_string())),
87	                None => (body, None),
88	            };
89	            let spec = lookup_long(&table, name)
90	                .ok_or_else(|| errors::unknown_flag(&format!("--{name}")))?;
91	            if !spec.takes_value && value.is_some() {
92	                return Err(errors::unhandled_argument(tok));
93	            }
94	            if let Some(c) = short_circuit(spec.long, mode) {
95	                return Ok(c);
96	            }
97	            options.flags.push((spec.long.to_string(), value));
98	        } else if tok.len() >= 2 && tok.starts_with('-') && tok != "--" {
99	            // Short flag: `-x` or `-x<attached value>`.
100	            let mut chars = tok[1..].chars();
101	            let c = chars.next().unwrap();
102	            let attached: String = chars.collect();
103	            let spec = lookup_short(&table, c)
104	                .ok_or_else(|| errors::unknown_flag(tok))?;
105	            if spec.takes_value {
106	                let value = if attached.is_empty() { None } else { Some(attached) };
107	                if let Some(cmd) = short_circuit(spec.long, mode) {
108	                    return Ok(cmd);
109	                }
110	                options.flags.push((spec.long.to_string(), value));
111	            } else {
112	                // Boolean short flag: only the bare form is recognized here.
113	                if !attached.is_empty() {
114	                    return Err(errors::unknown_flag(tok));
115	                }
116	                if let Some(cmd) = short_circuit(spec.long, mode) {
117	                    return Ok(cmd);
118	                }
119	                options.flags.push((spec.long.to_string(), None));
120	            }
121	        } else {
122	            // Positional token (a FILE, or the WORKDIR for interactive).
123	            positional.push(tok.clone());
124	        }
125	    }
126	
127	    // 3. Positional-arity validation that cmdargs performs at parse time.
128	    // Batch and test require at least one input FILE.
129	    if matches!(mode, Mode::Batch | Mode::Test) && positional.is_empty() {
130	        return Err(errors::no_input_files(mode));
131	    }
132	
133	    Ok(Command::Run(RunSpec { mode, positional, options }))
134	}
135	
136	/// Map an About flag to its terminal command, if it is one.
137	fn short_circuit(long: &str, mode: Mode) -> Option<Command> {
138	    match long {
139	        "help" => Some(Command::Help(mode)),
140	        "version" => Some(Command::Version),
141	        _ => None,
142	    }
143	}
144	
145	fn lookup_long<'a>(table: &'a [FlagSpec], name: &str) -> Option<&'a FlagSpec> {
146	    table
147	        .iter()
148	        .find(|f| f.long == name || f.aliases.contains(&name))
149	}
150	
151	fn lookup_short(table: &[FlagSpec], c: char) -> Option<&FlagSpec> {
152	    table.iter().find(|f| f.short == Some(c))
153	}
