1	//! Binary entry-point for the Rust `tamarin-prover` port.
2	//!
3	//! Stays small: parse argv → dispatch to [`tamarin_prover::run::run`]
4	//! → translate errors into a stderr message + non-zero exit code.
5	//!
6	//! Uses `mimalloc` as the global allocator, matching every other
7	//! tamarin entry-point in the workspace (`maude_prof`, `dump_proof`,
8	//! the `oracle_solver` test harness).  On wireguard.spthy's
9	//! `exists_session` the switch cuts ~4s off the prove loop versus
10	//! glibc malloc — the prover allocates millions of small Term/Subst
11	//! nodes during graph search and slab/region allocators are dramatically
12	//! cheaper for that churn pattern.
13	
14	#[global_allocator]
15	static GLOBAL: mimalloc::MiMalloc = mimalloc::MiMalloc;
16	
17	use std::process::ExitCode;
18	
19	fn main() -> ExitCode {
20	    let raw: Vec<String> = std::env::args().skip(1).collect();
21	    let args = match tamarin_prover::parse_args(&raw) {
22	        Ok(a) => a,
23	        Err(e) => {
24	            // HS-faithful: rc=1 for usage errors (CmdArgs's default).
25	            eprintln!("error: {}\n", e);
26	            eprintln!("{}", tamarin_prover::cli::help_text());
27	            return ExitCode::from(1);
28	        }
29	    };
30	    match tamarin_prover::run(&args) {
31	        Ok(0) => ExitCode::SUCCESS,
32	        Ok(n) => ExitCode::from(n.try_into().unwrap_or(1)),
33	        Err(e) => {
34	            // HS-faithful: rc=1 for runtime errors.
35	            eprintln!("error: {}", e);
36	            ExitCode::from(1)
37	        }
38	    }
39	}
