//! Workspace adapter routing this crate's `--help` / `--version` rendering
//! through the vendored clean-room console text modules (`super::help`,
//! `super::version`, `super::modes`). This file is pure type conversion and
//! data plumbing: it maps the ported [`super::Subcommand`] to the clean
//! [`Mode`] and fills the clean [`VersionInfo`] slots from this binary's own
//! build metadata (`super::VERSION` / `GIT_REV` / `GIT_BRANCH` /
//! `BUILD_TIMESTAMP`) and the detected Maude version. No render logic lives
//! here — the byte-exact HS text comes entirely from the clean modules.

use super::help::render_help;
use super::modes::Mode;
use super::version::{render_version, MaudeInfo, VersionInfo};
use super::Subcommand;

/// Map the ported subcommand to the clean text-surface mode.
fn mode_of(sub: &Subcommand) -> Mode {
    match sub {
        Subcommand::Batch => Mode::Batch,
        Subcommand::Interactive => Mode::Interactive,
        Subcommand::Variants => Mode::Variants,
        Subcommand::Test => Mode::Test,
    }
}

/// The byte-exact HS help page for the active subcommand.
pub fn help_text(sub: &Subcommand) -> &'static str {
    render_help(mode_of(sub))
}

/// The default (batch) help page — for callers with no subcommand in scope
/// (parse-error fallback, batch "no input files" envelope).
pub fn help_text_default() -> &'static str {
    render_help(Mode::Batch)
}

/// The full `--version` banner, byte-exact against the HS `--version` capture
/// (the interleaved 2>&1 form the clean template models), with this binary's
/// build metadata in the slots. Rendered as a single string printed to stdout;
/// unlike the removed ported path it does not split the maude self-check lines
/// onto stderr (the clean template does not model stream separation).
pub fn version_stdout() -> String {
    let maude_version =
        super::detect_maude_version_pub().unwrap_or_else(|| "unknown version".to_string());
    let info = VersionInfo {
        maude: MaudeInfo { path: "maude".to_string(), version: maude_version },
        tamarin_version: super::VERSION.to_string(),
        copyright_years: "2010-2023".to_string(),
        git_description: format!("{}, branch: {}", super::GIT_REV, super::GIT_BRANCH),
        compiled_at: super::BUILD_TIMESTAMP.to_string(),
    };
    render_version(&info)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn help_is_the_hs_global_page() {
        // Byte-exact against the vendored HS capture, and mode-selective.
        assert_eq!(help_text(&Subcommand::Batch), include_str!("fixtures/help_global.txt"));
        assert_eq!(help_text(&Subcommand::Interactive), include_str!("fixtures/help_interactive.txt"));
        assert_eq!(help_text(&Subcommand::Variants), include_str!("fixtures/help_variants.txt"));
        assert_eq!(help_text(&Subcommand::Test), include_str!("fixtures/help_test.txt"));
    }

    #[test]
    fn version_uses_clean_template_and_fills_slots() {
        let out = version_stdout();
        // Static template text (byte-exact HS) is present and interleaved.
        assert!(out.starts_with("maude tool: 'maude'\n checking version: tamarin-prover "));
        assert!(out.contains("This program comes with ABSOLUTELY NO WARRANTY."));
        assert!(out.contains("\n checking installation: OK.\nGenerated from:\n"));
        // Build-metadata slots are filled from this binary.
        assert!(out.contains(&format!("Tamarin version {}\n", super::super::VERSION)));
        assert!(out.contains(&format!("branch: {}\n", super::super::GIT_BRANCH)));
        assert!(out.ends_with("\n"));
    }
}

