pub fn expand_theory_macros(thy: &mut p::Theory) {
    // Whole-theory macro expansion is performed by the vendored clean-room
    // expander `crate::macros::expand`, which returns an equivalent macro-free
    // theory. That expander DROPS the `macros:` declarations, but callers of
    // `expand_theory_macros` (notably `elaborate`, which afterwards re-reads the
    // `Macros` items to register the macro fun-syms and retain the block) rely
    // on them staying in place, so this adapter re-merges: every non-macro item
    // is replaced by its expanded counterpart, and each `Macros` item is kept
    // untouched. The clean expander preserves the relative order of the
    // non-macro items, so a positional zip is exact.
    let expanded = crate::macros::expand(thy);
    let mut expanded_items = expanded.items.into_iter();
    for item in thy.items.iter_mut() {
        if matches!(item, p::TheoryItem::Macros(_)) {
            continue;
        }
        *item = expanded_items
            .next()
            .expect("clean expander yields one item per non-macro theory item");
    }
    debug_assert!(expanded_items.next().is_none());
}

