319	                let mapped: Option<Vec<LNTerm>> =
320	                    args.iter().map(bvar_term_to_lnterm).collect();
321	                mapped.map(|a| Term::App(sym.clone(), a.into()))
322	            }
323	        }
324	    }
325	
326	    // Candidate tags + their default shape.  Mirrors HS `candidates`
327	    // (InjectiveFactInstances.hs:121-138): `M.fromListWith combineShapes`
328	    // over `(tag, combineShapes (getShape conc) (getShape prem))` for each
329	    // (rule, conc, prem) with:
330	    //   guard $ (factTagMultiplicity tag == Linear)
331	    //        && (tag `elem` (factTag <$> rPrems ru))
332	    //   guard (factTag prem == tag)
333	    //   guard (not (null (factTerms conc)))
334	    //
335	    // The guards above must hold PER-RULE: a tag is injective only when a
336	    // SINGLE rule has it in both its premises and conclusions.  Including
337	    // any tag that merely appears as a conclusion in some rule is too
338	    // permissive — it adds spurious InjectiveFacts less-atoms (via
339	    // `nonInjectiveFactInstances`) for protocols whose linear facts get
340	    // *created* in one rule and *consumed* in another (no round-trip).
341	    // E.g. Artificial.spthy: Step1 creates St(x, k), Step2 consumes it —
342	    // neither rule has both → St is not injective (Fin_unique's case_2).
343	    // `M.fromListWith` folds DUPLICATE keys with `combineShapes` (note the
344	    // args are flipped vs. the first insert, but `combineShapes` is
345	    // symmetric in length-trimming), so we fold on insert.
346	    let mut candidates: BTreeMap<FactTag, Vec<Vec<MonotonicBehaviour>>> = BTreeMap::new();
347	    for &r in rules {
348	        let prem_tags: std::collections::BTreeSet<FactTag> = r.premises.iter()
349	            .map(|p| p.tag.clone()).collect();
350	        for conc in &r.conclusions {
351	            let tag = &conc.tag;
352	            if !matches!(tag, FactTag::Proto(_, _, _)) { continue; }
353	            if fact_tag_multiplicity(tag) != Multiplicity::Linear { continue; }
354	            if !prem_tags.contains(tag) { continue; }
355	            for prem in r.premises.iter().filter(|p| &p.tag == tag) {
356	                if conc.terms.is_empty() { continue; }
357	                let shape = combine_shapes(&get_shape(conc), &get_shape(prem));
358	                candidates.entry(tag.clone())
359	                    .and_modify(|existing| *existing = combine_shapes(existing, &shape))
360	                    .or_insert(shape);
361	            }
362	        }
363	    }
364	
365	    // HS `getMaybeEqStrict tag ru` (InjectiveFactInstances.hs:170-223): the
366	    // per-rule shape, or `Nothing` if the rule violates injectivity for the
367	    // tag.
368	    let get_maybe_eq_strict = |tag: &FactTag, r: &ProtoRuleE,
369	                               default_shape: &[Vec<MonotonicBehaviour>]|
370	        -> Option<Vec<Vec<MonotonicBehaviour>>> {
371	        let copies: Vec<&LNFact> = r.conclusions.iter()
372	            .filter(|c| &c.tag == tag).collect();
373	        // HS `constraints = concatMap extractConstraints
374	        //   (preRestriction (rInfo ru))` (InjectiveFactInstances.hs:177).
375	        let constraints: Vec<(LNTerm, LNTerm)> = r.info.restrictions.iter()
376	            .flat_map(extract_constraints).collect();
377	        // HS `duplicateFirstTerms` (InjectiveFactInstances.hs:181-182): the
378	        // first terms appearing at least twice among `copies`.
379	        let mut first_term_counts: BTreeMap<&LNTerm, usize> = BTreeMap::new();
380	        for c in &copies {
381	            if let Some(ft) = first_term(c) {
382	                *first_term_counts.entry(ft).or_insert(0) += 1;
383	            }
384	        }
385	        let duplicate_first_terms: std::collections::BTreeSet<&LNTerm> =
386	            first_term_counts.into_iter()
387	                .filter(|(_, n)| *n >= 2)
388	                .map(|(t, _)| t)
389	                .collect();
390	
391	        // HS `getMaybeEqMonConclusion` (InjectiveFactInstances.hs:185-223).
392	        let get_maybe_eq_mon_conclusion = |fa_conc: &LNFact|
393	            -> Option<Vec<Vec<MonotonicBehaviour>>> {
394	            let t_conc = first_term(fa_conc)?;          // Nothing if no args
395	            if duplicate_first_terms.contains(t_conc) {  // violating (2)
396	                return None;
397	            }
398	            if fresh_premise_for(r, t_conc) {            // applying (2)(a)
399	                return Some(default_shape.to_vec());
400	            }
401	            let fa_prem = copy_premise_for(r, tag, t_conc)?;  // violating (2)(b)
402	            // HS `getBehaviour` (InjectiveFactInstances.hs:213-219).
403	            let get_behaviour = |t1: &LNTerm, t2: &LNTerm| -> MonotonicBehaviour {
404	                if t1 == t2 {
405	                    Constant
406	                } else if crate::tools::subterm_store::elem_not_below_reducible(
407	                    reducible, t1, t2) {
408	                    StrictlyIncreasing
409	                } else if crate::tools::subterm_store::elem_not_below_reducible(
410	                    reducible, t2, t1) {
411	                    StrictlyDecreasing
412	                } else if constraints.iter().any(|(a, b)| a == t1 && b == t2) {
413	                    StrictlyIncreasing
414	                } else if constraints.iter().any(|(a, b)| a == t2 && b == t1) {
415	                    StrictlyDecreasing
416	                } else {
417	                    Unstable
418	                }
419	            };
420	            // HS `trimmedPairTerms` (InjectiveFactInstances.hs:205-207): unfold
421	            // each non-first term according to the default shape lengths.
422	            let shape_lens: Vec<usize> = default_shape.iter().map(|s| s.len()).collect();
423	            let trimmed = |fa: &LNFact| -> Vec<Vec<LNTerm>> {
424	                fa.terms.iter().skip(1).zip(shape_lens.iter())
425	                    .map(|(t, &n)| shape_term(t, n))
426	                    .collect()
427	            };
428	            let prem_leaves = trimmed(fa_prem);
429	            let conc_leaves = trimmed(fa_conc);
430	            // HS `zipped = zipWith zip (trimmedPairTerms faPrem)
431	            //   (trimmedPairTerms faConc)` then `map (map getBehaviour)`.
432	            let behaviours: Vec<Vec<MonotonicBehaviour>> = prem_leaves.iter()
433	                .zip(conc_leaves.iter())
434	                .map(|(ps, cs)| ps.iter().zip(cs.iter())
435	                    .map(|(p, c)| get_behaviour(p, c))
436	                    .collect())
437	                .collect();
438	            Some(behaviours)
439	        };
440	
441	        combine_all(copies.iter().map(|c| get_maybe_eq_mon_conclusion(c)),
442	            default_shape)
443	    };
444	
445	    // HS top-level: `tag <- M.keys candidates`;
446	    //   `combineAll (map (getMaybeEqStrict tag) rules) tag`.
447	    let mut out: Vec<(FactTag, Vec<Vec<MonotonicBehaviour>>)> = Vec::new();
448	    for (tag, default_shape) in &candidates {
449	        let per_rule = rules.iter()
450	            .map(|&r| get_maybe_eq_strict(tag, r, default_shape));
451	        if let Some(behaviours) = combine_all(per_rule, default_shape) {
452	            out.push((tag.clone(), behaviours));
453	        }
454	    }
455	    out
456	}
