470	/// Union the forced-injective fact tags into a computed
471	/// `simple_injective_fact_instances` result, mirroring HS `closeRuleCache`
472	/// (Rule.hs:147-150):
473	///
474	/// ```haskell
475	/// forcedInjFacts' = S.map (\x -> (x, replicate (factTagArity x) [Unspecified])) forcedInjFacts
476	/// injFactInstances = forcedInjFacts' `S.union` simpleInjectiveFactInstances ...
477	/// ```
478	///
479	/// Each forced tag carries `replicate arity [Unspecified]` as its behaviour
480	/// (one singleton `[Unspecified]` per argument position).  `S.union` keeps the
481	/// LEFT (forced) entry on a tag collision, then `S.toList` sorts by `Ord
482	/// FactTag`; we reproduce that with a tag-keyed merge + sort.
483	pub fn union_forced_injective_fact_instances(
484	    computed: Vec<(FactTag, Vec<Vec<MonotonicBehaviour>>)>,
485	    forced: &[FactTag],
486	) -> Vec<(FactTag, Vec<Vec<MonotonicBehaviour>>)> {
487	    use crate::fact::fact_tag_arity;
488	    use std::collections::BTreeMap;
489	    let mut map: BTreeMap<FactTag, Vec<Vec<MonotonicBehaviour>>> =
490	        computed.into_iter().collect();
491	    for tag in forced {
492	        // `S.union` is LEFT-biased; the forced entry wins on collision.
493	        let arity = fact_tag_arity(tag);
494	        let behaviour = vec![vec![MonotonicBehaviour::Unspecified]; arity];
495	        map.insert(tag.clone(), behaviour);
496	    }
497	    map.into_iter().collect()
498	}
