671	    // Haskell-faithfulness invariants — pinning the candidate filter
672	    // (#206: `Artificial::Fin_unique` regression).
673	    //
674	    // Mirrors Haskell `simpleInjectiveFactInstances`
675	    // (InjectiveFactInstances.hs:121-132):
676	    //
677	    //   guard $ (factTagMultiplicity tag == Linear)
678	    //        && (tag `elem` (factTag <$> rPrems ru))
679	    //
