265	/// Total order used to sort reported variables (see BEHAVIOR.md §6).
266	fn var_order_key(a: &VarSpec, b: &VarSpec) -> std::cmp::Ordering {
267	    sort_rank(a.sort)
268	        .cmp(&sort_rank(b.sort))
269	        .then_with(|| a.name.cmp(&b.name)) // lexicographic string comparison
270	        .then_with(|| a.idx.cmp(&b.idx)) // numeric index comparison
271	}
