273	/// Sort-tag rank. Observed among reportable (non-derivable) variables:
274	/// `Fresh < Msg`. Message-sort variables carry either `Msg` or `Untagged` and
275	/// rank together. Other sorts (`Pub`, `Node`, `Nat`, `Suffix`) do not occur as
276	/// reported variables — public names are always derivable and node/nat are not
277	/// message terms — so their relative rank is unobserved and placed last.
278	fn sort_rank(sort: SortHint) -> u8 {
279	    match sort {
280	        SortHint::Fresh => 0,
281	        SortHint::Msg | SortHint::Untagged => 1,
282	        _ => 2,
283	    }
284	}
