286	/// Render one variable as the reference tool spells it in the warning: fresh
287	/// names carry a `~` prefix, public names a `$` prefix, message names none; a
288	/// nonzero index is appended as `.idx` (e.g. `x.2`).
289	pub fn render_variable(v: &VarSpec) -> String {
290	    let prefix = match v.sort {
291	        SortHint::Fresh => "~",
292	        SortHint::Pub => "$",
293	        _ => "",
294	    };
295	    if v.idx == 0 {
296	        format!("{}{}", prefix, v.name)
297	    } else {
298	        format!("{}{}.{}", prefix, v.name, v.idx)
299	    }
300	}
