302	/// The per-rule block body: `"Rule <name>: \nFailed to derive Variable(s): <v1>, <v2>, ..."`.
303	/// Note the trailing space after the colon on the first line.
304	fn rule_block(rule_name: &str, vars: &[VarSpec]) -> String {
305	    let list = vars
306	        .iter()
307	        .map(render_variable)
308	        .collect::<Vec<_>>()
309	        .join(", ");
310	    format!("Rule {}: \nFailed to derive Variable(s): {}", rule_name, list)
