127	        // whose body uses a fresh-introducing macro is silently skipped; and
128	        // without let-block substitution, RS flags every let-bound name
129	        // (`pkB`, `mtr`, `ci2`, ...) as non-derivable.
130	        let macro_expanded;
131	        let macro_src = if theory_macros.is_empty() {
132	            raw_rule
133	        } else {
134	            macro_expanded = apply_theory_macros_to_rule(raw_rule, &theory_macros);
135	            &macro_expanded
136	        };
137	        let expanded = crate::elaborate::apply_let_block(macro_src);
138	        let rule = &expanded;
139	        let free_vars = collect_rule_free_vars(rule, &nullary_funs);
140	        if free_vars.is_empty() { continue; }
141	        rule_count += 1;
142	
143	        // Build the probe theory ONCE per rule (it contains all the
144	        // per-variable lemmas).  The synthesised theory is small —
145	        // one rule, N lemmas, the original signature.
146	        let t_synth = std::time::Instant::now();
147	        let probe = synthesise_probe_theory(parsed, rule, idx, &free_vars);
148	        let synth_dt = t_synth.elapsed();
149	        total_synth += synth_dt;
150	        if dbg {
151	            eprintln!("[deriv] rule={} free_vars={:?}", rule.name,
152	                free_vars.iter().map(|v| &v.name).collect::<Vec<_>>());
153	            eprintln!("[deriv] probe theory items:");
154	            for it in &probe.items {
155	                match it {
156	                    p::TheoryItem::Rule(r) => eprintln!("  rule {}: prem={} act={} conc={}",
157	                        r.name, r.premises.len(), r.actions.len(), r.conclusions.len()),
158	                    p::TheoryItem::Lemma(l) => eprintln!("  lemma {} ({:?})",
159	                        l.name, l.trace_quantifier),
160	                    _ => {}
161	                }
162	            }
163	        }
164	
165	        // Try each variable's lemma.  HS's "TraceFound" status maps
166	        // to RS's `NodeStatus::Solved` for exists-trace lemmas.
167	        //
168	        // HS-faithful structure: `closeTheoryWithMaude` is called ONCE
169	        // per probe theory (HS `MessageDerivationChecks.hs:40-44`
170	        // calls `closeTheoryWithMaude` once per modified theory; then
171	        // `proveTheory` walks the N lemmas reusing the closed theory's
172	        // sources/cache — `Prover.hs:260-279`).  `prove_probe` mirrors
173	        // this: build the `ProofContext` + run `ensure_saturated()` ONCE
174	        // per probe, then iterate the per-variable lemmas reusing it.
175	        let outcome = match prove_probe(&probe, maude.clone(), idx, &free_vars, timeout, dbg_timing, &rule.name) {
176	            Some(o) => o,
177	            None => continue,
178	        };
179	        // Fold the probe's debug-only timing/count into the running totals.
180	        total_prove += outcome.prove_time;
181	        var_count += outcome.var_count;
182	        let undecidable = outcome.undecidable;
183	        if dbg_timing {
184	            eprintln!(
185	                "[deriv-timing] rule={} synth={:.3}s nvars={} total_prove={:.3}s",
186	                rule.name, synth_dt.as_secs_f64(), free_vars.len(),
187	                total_prove.as_secs_f64(),
188	            );
189	        }
190	        if !undecidable.is_empty() {
191	            per_rule.push((rule.name.clone(), undecidable));
192	        }
193	    }
194	    if dbg_timing {
195	        eprintln!(
196	            "[deriv-timing] TOTAL rules={} vars={} synth={:.3}s prove={:.3}s wall={:.3}s",
197	            rule_count, var_count,
198	            total_synth.as_secs_f64(),
199	            total_prove.as_secs_f64(),
200	            t_total_start.elapsed().as_secs_f64(),
201	        );
202	    }
203	    format_deriv_report(&per_rule)
204	}
